using LEGAL.Shared.Helpers;using Serilog;
EnvLoader.Load();
Log.Logger=new LoggerConfiguration().MinimumLevel.Information().MinimumLevel.Override("Microsoft",Serilog.Events.LogEventLevel.Warning).MinimumLevel.Override("Yarp",Serilog.Events.LogEventLevel.Warning).WriteTo.Console().WriteTo.File("logs/gateway-.log",rollingInterval:RollingInterval.Day,retainedFileCountLimit:30).CreateLogger();
try{Log.Information("LEGAL Gateway starting on port 5220...");var builder=WebApplication.CreateBuilder(args);builder.Host.UseSerilog();builder.Services.AddReverseProxy().LoadFromConfig(builder.Configuration.GetSection("ReverseProxy"));builder.Services.AddCors(o=>{o.AddDefaultPolicy(p=>p.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader());});builder.Services.AddEndpointsApiExplorer();builder.Services.AddSwaggerGen(c=>{c.SwaggerDoc("v1",new(){Title="LEGAL Gateway",Version="v1"});});builder.Services.AddHealthChecks();var app=builder.Build();app.UseSerilogRequestLogging();app.UseCors();if(app.Environment.IsDevelopment()){app.UseSwagger();app.UseSwaggerUI();}app.MapHealthChecks("/api/health");app.MapReverseProxy();app.Run();}catch(Exception ex){Log.Fatal(ex,"LEGAL Gateway terminated");}finally{Log.CloseAndFlush();}
